  ('8aa855c8-51fd-481e-bfb9-88925be47efe', $$Scheikunde$$, $$VWO$$, $$Cadmiumgeel$$, $$VWO Scheikunde 2022-II$$),
  ('69ab6640-d7f1-4398-8524-b1552c99c99a', $$Scheikunde$$, $$VWO$$, $$Merox$$, $$VWO Scheikunde 2022-II$$),
  ('4af4c016-c0d5-4d48-b119-4dab2e7d9623', $$Scheikunde$$, $$VWO$$, $$EPDM-rubber$$, $$VWO Scheikunde 2022-II$$),
