   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-cadmiumgeel-vraag1.png$$, $$Geef de vergelijking van deze vorming van cadmiumsulfide uit zwavel en cadmiumcarbonaat.$$, array['e973827d-1654-434f-934f-0e3cd36dc707']::uuid[]),
  ('73e3d8d5-2095-4b64-94ac-154e92eeccb3', '8aa855c8-51fd-481e-bfb9-88925be47efe', 2,
