   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-cadmiumgeel-vraag5.png$$, $$Geef een mogelijke verhoudingsformule van het gevonden zout.$$, array['27e39293-e59c-440d-8c01-a3cab7f97734', '6298aa1d-8c49-4456-ab75-7b17dfff0cc2']::uuid[]),
