   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-merox-vraag9.png$$, $$Geef de vergelijking van de reactie die verloopt in R2.$$, array['191c11ed-4621-4d26-81af-95abdbb066f9', 'd30eac72-63b9-47cc-9672-a3aba37bb4e7', 'ea753f81-1127-4050-bcfa-f9d9887455f2']::uuid[]),
