   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-epdm-rubber-vraag14.png$$, $$Leg uit of toepassing van een katalysator type 2 bij de polymerisatie leidt tot een groter of kleiner percentage kristallijne gebieden. Gebruik hierbij Binas-tabel 66F of ScienceData-tabel 11.1.3.$$, array['4e976636-509b-4467-b892-c2372a281ab9']::uuid[]),
  ('d57a9eb7-f603-4d99-9026-e0f84705977e', '4af4c016-c0d5-4d48-b119-4dab2e7d9623', 15,
