   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-epdm-rubber-vraag15.png$$, $$Leg uit dat t-EPDM met een groot percentage kristallijne gebieden een kleinere vervormbaarheid heeft dan t-EPDM met een klein percentage kristallijne gebieden. Gebruik hierbij begrippen op microniveau.$$, array['e993952b-7c94-4bc3-a356-2ab377cfd09a']::uuid[]),
  ('77ce5e79-474e-4c0b-bdf8-4a9e5ab3eb5d', '4af4c016-c0d5-4d48-b119-4dab2e7d9623', 16,
