   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-epdm-rubber-vraag16.png$$, $$Leg uit of het gehalte ¹⁴C in Keltan®-Eco hoger of lager is dan in EPDM-rubber dat is geproduceerd op basis van fossiele grondstoffen.$$, array['f14ca365-cf72-49d0-9ea4-f42b24f22a97', 'e7d9547d-d019-4679-b155-92503260f966']::uuid[]),
  ('6027fea1-62ed-4ea0-8092-25725db702d5', '4af4c016-c0d5-4d48-b119-4dab2e7d9623', 17,
   '[{"domain": "Reacties", "subdomain": "Exotherme en endotherme reacties"}]'::jsonb,
