   $$https://rfyffbietarhprlbvdek.supabase.co/storage/v1/object/public/practice-question-images/scheikunde-vwo-2022-ii-voedsellijm-vraag22.png$$, $$Maak de vergelijking op de uitwerkbijlage compleet en geef de naam van de aminozuureenheid die hierbij wordt gevormd.$$, array['28d2f30c-be39-4149-868d-6cf6a5c4c2bd', '43e8333e-c6ca-4835-8b5f-4f1c36345313']::uuid[]),
  ('048bd599-7737-4d37-b6af-b0d1179c2604', 'a6396614-da5f-42d5-a097-1c66504f2812', 23,
